module shift_register_8bit(
    input [7:0] d, 
    input load, 
    input clk, 
    output q
);
    reg [7:0] data_buffer;

    always @(posedge clk) begin
        if (load)
            data_buffer <= d;
        else
            data_buffer <= data_buffer >> 1;
    end

    assign q = data_buffer[0];
endmodule
